import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Check if the input length exceeds the buffer size
        if (name.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        byte[] buffer = new byte[10];
        Arrays.fill(buffer, (byte) 0); // Clear the buffer

        // Copy input data into the buffer
        byte[] nameBytes = name.getBytes();
        System.arraycopy(nameBytes, 0, buffer, 0, Math.min(nameBytes.length, buffer.length));

        System.out.println("Hello, " + new String(buffer).trim()); // Trim to remove trailing zeros
    }
}

### Explanation:
취약유형: Buffer Overflow
